const TILBURG_GIS = "https://services-eu1.arcgis.com/CQPBPtVdeDfydflM/arcgis/rest/services";

function tilburg(
  service: string,
  layerId: number,
  serverType: "FeatureServer" | "MapServer" = "FeatureServer",
  maxFeatures = 2000,
  full = false
) {
  return fetchArcGISQuery(TILBURG_GIS, service, layerId, serverType, maxFeatures, full);
}

